CODE_EXAMPLE:
// Order exposes only what callers need
class Order {
    private final Customer customer;
    public String getCustomerCity() { return customer.getCity(); }
}

class Customer {
    private final Address address;
    public String getCity() { return address.getCity(); }
}

// Caller uses one dot
String city = order.getCustomerCity();

UNIT_TEST_EXAMPLE:
@Test
public void getCustomerCity_returnsCityFromAddress() {
    Address address  = new Address("Springfield");
    Customer customer = new Customer(address);
    Order order      = new Order(customer);
    assertEquals("Springfield", order.getCustomerCity());
}
